// Worked focus: httpsts-proxy-drain-upgrade-evidence — Test keep-alive reuse, upgrades, CONNECT, streaming, trailers, retries, draining, malformed requests, and changed proxy topology with wire evidence.
// Evidence: httpsts-worked-http-server-ts-proxy-framing-smuggling-4
// Competency: httpsts-worked-http-server-ts-proxy-framing-smuggling-4.
// Case 1655: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: abort during a dependency phase and preserve cleanup plus response ownership.
function worked_http_server_ts_proxy_framing_smuggling_4(trustedHops: number, contentLengthCount: number, hasTransferEncoding: boolean, insecureParser: boolean): { forward: boolean; reason: string } {
  if (trustedHops < 0 || trustedHops > 2) return { forward: false, reason: "forwarded-topology" };
  if (contentLengthCount !== 1 || hasTransferEncoding) {
    return { forward: false, reason: "ambiguous-framing" };
  }
  if (insecureParser) return { forward: false, reason: "parser-policy" };
  return { forward: true, reason: "consistent-hops" };
}

